        return 0;
    }
    if (tx < sx || ty < sy) {
        return -1;
    }
    if (tx == ty) {
        return -1;
    }

    long count = 0;
    while (tx >= sx && ty >= sy) {
        if (tx == sx && ty == sy) {
            return count;
        }
        if (tx == ty) {
            return -1;
        }

        if (tx > ty) {
