                } else {
                    return -1;
                }
            } else {
                long k = (tx - sx) / ty;
                if (k == 0) {
                    k = 1;
                }
                count += k;
                tx -= k * ty;
            }
        } else {
            if (tx == sx) {
                if (ty - sy >= 0) {
                    long diff = ty - sy;
                    if (diff % tx == 0) {
                        count += diff / tx;
                        return count;
                    } else {
