                }
            } else {
                long k = (ty - sy) / tx;
                if (k == 0) {
                    k = 1;
                }
                count += k;
                ty -= k * tx;
            }
        }
    }

    if (tx == sx && ty == sy) {
        return count;
    } else {
        return -1;
    }
}
